INSERT INTO "public"."song_analysis" ("id", "song_id", "analysis", "model", "prompt_version", "tokens_used", "cost_cents", "created_at", "updated_at", "provider", "input_tokens", "output_tokens", "cost_usd") VALUES
	('b36ac547-2033-4c89-883f-6b724dd1e025', 'd23c619e-e097-419d-89b5-263800ce70fa', '{"headline": "A quiet understanding of moments passed, holding onto the bittersweet ache of memory.", "compound_mood": "Echoing Melancholy", "sonic_texture": "Warm, shimmering synth pads swell and recede, painting vast, open spaces. Underneath, a deep, resonant bass provides a quiet anchor, as delicate electronic arpeggios twinkle like distant stars. A gentle, insistent beat pulses, giving everything a soft forward momentum.", "audio_features": {"tempo": 127.945, "energy": 0.472, "valence": 0.0424, "liveness": 0.11, "loudness": -9.277, "speechiness": 0.0739, "acousticness": 0.534, "danceability": 0.525, "instrumentalness": 0.614}, "mood_description": "A gentle pulse moves through you, a quiet hum that pulls at something deep inside. You feel a familiar ache, like a moment caught between wistful remembering and the quiet acceptance of time passing."}', 'google:gemini-2.5-flash', '2', 2484, NULL, '2026-04-08 05:26:25.784521+00', '2026-04-08 05:26:25.784521+00', NULL, NULL, NULL, NULL),
	('904579b2-6463-4694-b69d-0aa65ccc3063', '2e151589-3139-4afd-8d08-2d91e94fb857', '{"themes": [{"name": "testing commitment", "description": "Challenging a potential partner to prove their sincerity and effort before a connection deepens."}, {"name": "playful elusiveness", "description": "The enjoyment and power found in being hard to catch, keeping someone intrigued and on their toes."}, {"name": "self-preservation in dating", "description": "Protecting oneself from superficial connections by maintaining a readiness to leave if expectations aren''t met."}, {"name": "the desire for permanence", "description": "Despite the game of chase, a quiet wish for someone to be truly exceptional and make the act of disappearing unnecessary."}], "journey": [{"mood": "Bold, evasive", "section": "Opening Challenge", "description": "A confident declaration sets the tone, announcing an inclination to leave as quickly as arriving, daring someone to keep up."}, {"mood": "Inviting, fleeting", "section": "Observational Flirtation", "description": "Watching and inviting closeness, but underscoring the precious, limited nature of the moment, a silent challenge to act."}, {"mood": "Hopeful, conditional", "section": "Vulnerable Opening", "description": "A surprising shift reveals a crack in the playful facade, admitting a deep desire for someone to be significant enough to make staying an option."}, {"mood": "Skeptical, direct", "section": "Demanding Verification", "description": "Sweet words aren''t enough; a demand for genuine action and belief-inspiring effort, needing more than just talk."}, {"mood": "Insistent, playful", "section": "Echoing Promise", "description": "The core challenge echoes one last time, a final reminder of the escape artist''s nature, leaving the ball in the other''s court."}], "headline": "A thrilling game of chase, daring a lover to prove their worth before disappearing into the night.", "key_lines": [{"line": "I''m not here for long", "insight": "The scarcity creates value, making every moment a test of genuine interest."}, {"line": "Catch me or I go Houdini", "insight": "A clear warning: engage fully or face the consequences of inaction and a swift departure."}, {"line": "It''s your moment, baby, don''t let it slip", "insight": "Seizing the opportunity before it vanishes is the ultimate proof of their dedication."}, {"line": "Maybe you could be the one to make me stay", "insight": "Beneath the detachment, a surprising vulnerability and a wish for a truly lasting connection."}, {"line": "But do you practise everything that you preach?", "insight": "Skepticism of words alone, demanding actions to match promises and build trust."}], "compound_mood": "Elusive Challenge", "sonic_texture": "Pulsing basslines and shimmering synths create a vibrant, propulsive dance groove. The rhythm feels both effortless and insistent, like a playful chase unfolding on a crowded dancefloor, topped with clear, confident vocals.", "interpretation": "Setting a clear ultimatum in a potential romance, a confident declaration that one must earn commitment or face swift departure. There''s a self-protective stance, but also a hidden hope that someone might be ''good enough'' to make them change their fleeting ways.", "mood_description": "A flirtatious energy pulses, a confident dare wrapped in a vibrant, almost insistent rhythm. It feels like setting the terms for a high-stakes romance, a game only one person can win."}', 'google:gemini-2.5-flash', '2', 6240, NULL, '2026-04-08 05:26:43.582518+00', '2026-04-08 05:26:43.582518+00', NULL, NULL, NULL, NULL),
	('b035839c-96e3-468e-801a-778d8fb43e6b', '08864488-ec58-4791-a31e-1bf3db5bda5a', '{"themes": [{"name": "unrequited futures", "description": "One person dreams of ''forever'' while the other seems to live in the moment, creating an emotional rift."}, {"name": "defensive vulnerability", "description": "Masking deep feelings with dismissive lines, attempting to protect a wounded heart."}, {"name": "enduring first love", "description": "The indelible mark of a transformative first experience, kept alive in spirit even after the relationship ends."}, {"name": "emotional imbalance", "description": "The stark contrast between one person''s overwhelming feelings and the other''s perceived apathy."}], "journey": [{"mood": "Quiet admission", "section": "Verse 1", "description": "Life was a mess before, and now the calm brought by another is gone, leaving a heavy rainfall of tears."}, {"mood": "Desperate uncertainty", "section": "Pre-Chorus", "description": "The realization hits, bringing a desperate uncertainty while wondering if they feel anything close to the same."}, {"mood": "Aching question", "section": "Chorus", "description": "A future is imagined, full of ''forever,'' but there''s a painful doubt if the other person even considers such a thing."}, {"mood": "Feigned indifference", "section": "Verse 2", "description": "A flash of anger and defensiveness emerges, dismissing the connection, even as the longing pushes through."}, {"mood": "Profound confession", "section": "Bridge", "description": "The memory of a first, transformative love comes flooding back, something so fundamental it could never truly fade."}, {"mood": "Solitary yearning", "section": "Outro", "description": "The aching question returns, as the ''forever'' that was once a shared dream now feels like a solitary, unanswered plea."}], "headline": "A tender, obsessive plea for a love that might only exist in memory.", "key_lines": [{"line": "My eyes don''t shed tears, but boy, they pour", "insight": "The outward expression of sadness is muted, but internally, the grief is overwhelming."}, {"line": "Or do you not think so far ahead?", "insight": "A quiet, devastating fear that love is not equally felt or considered."}, {"line": "No, I don''t like you, I just thought you were cool enough to kick it", "insight": "A self-protective lie, trying to diminish a profound connection to avoid further hurt."}, {"line": "You know you were my first time", "insight": "The indelible, foundational nature of this past relationship, forever etched into memory."}, {"line": "We''ll go down this road ''til it turns from color to black and white", "insight": "A commitment to carrying the memory, even as time fades its vividness."}], "compound_mood": "Tender Desperation", "sonic_texture": "Smooth, echoing synths drift over a relaxed, yet subtly propulsive beat. Frank''s layered vocals float with an ethereal, almost mournful quality, creating a warm, hazy soundscape that belies the emotional weight of the words. The bassline is soft but ever-present, guiding the sad, danceable rhythm.", "audio_features": {"tempo": 129.83, "energy": 0.339, "valence": 0.2, "liveness": 0.0973, "loudness": -11.195, "speechiness": 0.0532, "acousticness": 0.409, "danceability": 0.721, "instrumentalness": 0.00153}, "interpretation": "The raw, often contradictory feelings of a broken first love emerge here. It’s a battle between feigned indifference and profound yearning, where one person imagines a shared future while the other remains a mystery. The smooth, almost laid-back production creates a stark contrast to the emotional turmoil in the words, highlighting the internal struggle to maintain composure even as a deep wound is exposed. It’s the agony of knowing you felt everything, and wondering if they felt anything at all.", "mood_description": "A yearning confession floats over a deceptively smooth and danceable groove. It''s a sad sway, caught between reliving a first love and the ache of its fading."}', 'google:gemini-2.5-flash', '2', 6314, NULL, '2026-04-08 05:27:05.219535+00', '2026-04-08 05:27:05.219535+00', NULL, NULL, NULL, NULL),
	('001abd79-85c7-4d6b-851f-928d1a9eb11d', '8dc3d88e-cf16-494e-8471-40cdd2df561c', '{"themes": [{"name": "post-breakup turmoil", "description": "The confusing, contradictory feelings that remain long after a relationship ends, blending anger, longing, and a strange sense of relief."}, {"name": "imbalanced power dynamics", "description": "Unpacking a relationship where one person held significant control, using manipulation and age difference to their advantage."}, {"name": "reclaiming self", "description": "The difficult, ongoing process of finding your own voice and strength after being silenced or diminished by a partner."}, {"name": "the ghost of abuse", "description": "The haunting presence of a former abuser''s behavior, making it hard to find peace or move on completely."}], "journey": [{"mood": "Raw contradiction", "section": "Verse 1", "description": "A confession of conflicting feelings, both sharp and childlike, immediately followed by the sting of manipulation and faked connection."}, {"mood": "Overwhelming nausea", "section": "Chorus", "description": "The sudden jolt of emotional motion sickness, a desperate plea to escape an inescapable presence that follows everywhere."}, {"mood": "Cold clarity", "section": "Verse 2", "description": "Stepping back to see the wreckage, finding a quiet, conflicted relief in having escaped the chaos, even while acknowledging the pain it caused."}, {"mood": "Flickers of defiance", "section": "Chorus (extended)", "description": "Direct confrontation with the past, attempting to claw back agency with subtle jabs, trying to drown out the lingering echoes even if the fight feels impossible."}, {"mood": "Stark imbalance", "section": "Bridge", "description": "The unsettling revelation of a predatory age gap, laying bare the unsettling power dynamic and the ex''s jaded motivation."}, {"mood": "Worn resignation", "section": "Final Chorus", "description": "A final, weary attempt to break free, invoking the language of addiction as it contemplates surrendering to the overwhelming pull of the past."}], "headline": "The dizzying aftermath of a toxic love, where hate and longing spin in an endless loop.", "key_lines": [{"line": "I hate you for what you did And I miss you like a little kid", "insight": "The bewildering internal tug-of-war between fury and childlike yearning after a breakup, a messy, human contradiction."}, {"line": "I have emotional motion sickness", "insight": "The physical manifestation of a chaotic internal state, a dizzying inability to find stillness or peace."}, {"line": "You were in a band when I was born", "insight": "The chilling revelation of a predatory age gap, laying bare the unsettling power dynamic at the heart of the relationship."}, {"line": "But I will try to drown you out", "insight": "A shift from passive overwhelm to active, though still desperate, resistance against the lingering influence of a past love."}, {"line": "If I surrender to the sound", "insight": "The agonizing consideration of letting go and giving in, even if it means succumbing to the very chaos fought against."}], "compound_mood": "Wounded Disorientation", "sonic_texture": "Warm, strumming acoustic guitars with a steady, propulsive rhythm section. Vocals are clear and direct, cutting through a slightly melancholic, yet engaging, indie-folk soundscape.", "audio_features": {"tempo": 107.021, "energy": 0.546, "valence": 0.623, "liveness": 0.0842, "loudness": -9.021, "speechiness": 0.0357, "acousticness": 0.774, "danceability": 0.651, "instrumentalness": 0.0437}, "interpretation": "Escaping a toxic relationship doesn''t always mean escaping its emotional residue. It''s a messy, contradictory fight to reconcile lingering attachment with sharp resentment, constantly replaying the past while trying desperately to move forward.", "mood_description": "A feeling of being perpetually off-kilter, wrestling with conflicting emotions that refuse to settle. It''s catchy and moving, like dancing through a heavy fog."}', 'google:gemini-2.5-flash', '2', 5367, NULL, '2026-04-08 05:27:21.900426+00', '2026-04-08 05:27:21.900426+00', NULL, NULL, NULL, NULL),
	('f7ad4a1d-071d-4d33-91fc-0c407dd6753c', '6714100d-0719-4372-ba4d-0ab5d654386b', '{"themes": [{"name": "irreconcilable differences", "description": "Two individuals, deeply fond of each other, find their fundamental ways of life are simply too far apart."}, {"name": "hedonism vs. discipline", "description": "The clash between a free-spirited, late-night existence and a meticulous, early-morning routine."}, {"name": "playful rejection", "description": "A kindhearted, almost teasing acknowledgment that someone''s ''sweetness'' is lovely, but ultimately not a fit."}, {"name": "self-acceptance", "description": "Embracing one''s own habits and preferences, even when they diverge from a partner''s expectations or desires."}], "journey": [{"mood": "Playful Observation", "section": "Verse 1", "description": "Waking late, grumpy, and observing a partner''s perfect, disciplined life with a mix of awe and mild disbelief."}, {"mood": "Cheeky Challenge", "section": "Pre-Chorus", "description": "A direct, teasing question inviting a partner to shed their inhibitions and embrace a wilder, more carefree moment."}, {"mood": "Confident Declaration", "section": "Chorus", "description": "The ultimate statement: a firm commitment to one''s own ''neat'' preferences, recognizing the stark, but not bitter, incompatibility."}, {"mood": "Assertive Explanation", "section": "Verse 2", "description": "A deeper dive into one''s own work-late, aim-low philosophy, contrasting it with a partner''s meticulous self-care, acknowledging the beauty but also the distance."}, {"mood": "Wry Longing", "section": "Pre-Chorus (Reprise)", "description": "Admiring the partner''s inherent sweetness while playfully suggesting a desire for them to become ''aged'' and ''bitter'' like a fine whiskey, knowing it''s a pipe dream."}, {"mood": "Firm Acceptance", "section": "Outro", "description": "The final, unyielding embrace of one''s chosen path, reiterating the core truth that some differences are simply too sweet to overcome."}], "headline": "A playful rejection, acknowledging that some loves simply can''t bridge fundamental differences in how life is lived.", "key_lines": [{"line": "Don''t you just wanna wake up, dark as a lake / Smellin'' like a bonfire, lost in a haze?", "insight": "A yearning for shared wildness, inviting another to shed their inhibitions and experience life less strictly."}, {"line": "I think I''ll take my whiskey neat / My coffee black and my bed at 3", "insight": "Embracing a life lived on one''s own terms, unbound by conventional timelines or tastes."}, {"line": "You treat your mouth as if it''s Heaven''s gate / The rest of you like you''re the TSA", "insight": "A pointed, vivid image of rigid self-regulation and strictness, bordering on comedic."}, {"line": "If you can sit in a barrel, maybe I''ll wait", "insight": "A witty, slightly teasing hope for a partner to become more seasoned and complex, like aged alcohol."}, {"line": "You''re too sweet for me", "insight": "A lighthearted declaration of incompatibility, rooted in fundamental differences rather than a lack of affection."}], "compound_mood": "Sardonic Affection", "sonic_texture": "A vibrant, blues-infused rock groove driven by a punchy bassline and crisp drums, topped with Hozier''s signature soulful, soaring vocals and hints of gospel-tinged harmonies. It''s danceable and energetic, with a classic, full-bodied feel that makes you want to move.", "audio_features": {"tempo": 117.038, "energy": 0.62, "valence": 0.934, "liveness": 0.0398, "loudness": -5.505, "speechiness": 0.0412, "acousticness": 0.0295, "danceability": 0.741, "instrumentalness": 0.000809}, "interpretation": "Recognizing that even deep affection can''t overcome two vastly different approaches to life. It''s a declaration of self-acceptance, choosing to stay true to one''s own nature rather than conform, even if it means letting go of someone adored. The story here isn''t one of heartbreak, but of a cheerful, self-aware parting of ways.", "mood_description": "A confident, funky groove carries a cheeky observation about incompatible lifestyles. It''s a knowing smile at a love that''s just too pure to last."}', 'google:gemini-2.5-flash', '2', 5731, NULL, '2026-04-08 05:27:36.340166+00', '2026-04-08 05:27:36.340166+00', NULL, NULL, NULL, NULL),
	('ac459b30-cea5-4bce-8aea-cce5c04e5ff7', '429d8a32-b808-47be-b3cb-7ada5081f334', '{"themes": [{"name": "obsessive longing", "description": "An inescapable mental loop, replaying interactions and questioning every subtle, unspoken signal."}, {"name": "desperate pursuit", "description": "A relentless, almost undignified effort to re-establish a connection, regardless of the emotional cost."}, {"name": "emotional uncertainty", "description": "Navigating the agonizing space between hoping for mutual feelings and fearing rejection."}], "journey": [{"mood": "Anxious Probing", "section": "Verse 1", "description": "A string of intimate, uneasy questions, dissecting every subtle signal and wondering if there''s a hidden truth. The feeling of someone entirely consumed by another''s presence, even in dreams."}, {"mood": "Hesitant Inquiry", "section": "Pre-Chorus", "description": "The crucial question finally surfaces, a hesitant whisper of whether these intense feelings are returned. There''s a bittersweet acknowledgment of how alcohol loosens tongues, revealing unspoken truths."}, {"mood": "Magnetic Helplessness", "section": "Chorus", "description": "An admission of total surrender to an undeniable pull, confessing to repeatedly returning to the same person, unable to move on. It’s a desperate confession of being utterly consumed and bound."}, {"mood": "Bold Uncertainty", "section": "Verse 2", "description": "A shift to more direct, almost daring questions, pushing for an answer about the other person''s heart. Yet, the deep insecurity remains, unsure if the desire for a kiss is shared."}, {"mood": "Lingering Doubt", "section": "Outro", "description": "The core questions echo and repeat, fading out unresolved, a testament to the persistent, nagging uncertainty that refuses to disappear. The feeling of being stuck in an endless loop of wanting."}], "headline": "A low hum of obsession, driven by endless questions and a desperate magnetic pull to someone you can''t shake.", "key_lines": [{"line": "How many secrets can you keep?", "insight": "The emotional distance felt from someone holding back."}, {"line": "(Do I wanna know) If this feelin'' flows both ways?", "insight": "The terrifying vulnerability of hoping for mutuality."}, {"line": "Maybe I''m too busy bein'' yours to fall for somebody new", "insight": "The complete devotion that makes moving on impossible."}, {"line": "Do you want me crawlin'' back to you?", "insight": "The ultimate fear that one''s desperate return isn''t actually desired."}], "compound_mood": "Magnetic Desperation", "sonic_texture": "A dark, slinky guitar riff leads the way, accompanied by a heavy, steady drum beat and a deep, pulsing bassline. The vocals are a cool, almost detached murmur, carrying a potent undercurrent of longing, all wrapped in a smooth, studio-polished haze.", "audio_features": {"tempo": 85.03, "energy": 0.532, "valence": 0.405, "liveness": 0.217, "loudness": -7.596, "speechiness": 0.0323, "acousticness": 0.186, "danceability": 0.548, "instrumentalness": 0.000263}, "interpretation": "Consumed by uncertainty and an inescapable pull, desperately searching for any sign of mutual feeling from someone who seems distant or indifferent. The internal monologue is a restless loop of ''do I wanna know?'' as an unshakeable connection binds, even if it''s painful and one-sided.", "mood_description": "A hazy, slow-burning groove pulls you into a swirl of unanswered questions. Every beat feels like a persistent echo of someone you can''t get out of your head."}', 'google:gemini-2.5-flash', '2', 6513, NULL, '2026-04-08 05:27:54.873983+00', '2026-04-08 05:27:54.873983+00', NULL, NULL, NULL, NULL),
	('652ad697-c959-4d2a-9b82-1cf599a95246', '1a28ed64-772b-4e69-8ad8-719c898c6019', '{"themes": [{"name": "possessive obsession", "description": "The consuming desire to control a past lover, even when it leads to destructive thoughts and actions."}, {"name": "fear of abandonment", "description": "A deep-seated dread of being left alone, making drastic, even violent, alternatives seem preferable to solitude."}, {"name": "performative maturity", "description": "The ironic claim of personal growth and therapy, immediately undercut by the inability to move past a singular, unhealthy desire."}], "journey": [{"mood": "Bitter reflection", "section": "Verse 1", "description": "Watching from a distance, the hurt turns into a simmering resentment at someone else''s happiness, a quiet admission of lingering attachment."}, {"mood": "Ironic self-talk", "section": "Pre-Chorus", "description": "Professing maturity and therapy-driven growth, but immediately backtracking to a singular, all-consuming desire that refuses to be reasoned with."}, {"mood": "Unsettling fantasy", "section": "Chorus", "description": "The idea of extreme action floats to the surface, a chilling thought wrapped in a confession of enduring love and the unbearable weight of solitude."}, {"mood": "Escalating fixation", "section": "Verse 2", "description": "The realization of true loss hardens into concrete plans, the mundane turning sinister as dark fantasies are meticulously detailed."}, {"mood": "Dark justification", "section": "Bridge", "description": "Rationalizing intense, premeditated actions as being ''all for love,'' a sober decision made out of deep, unwavering devotion."}, {"mood": "Fantasy realized", "section": "Chorus (Outro)", "description": "A chilling, almost casual admission of crossing a line, still anchored by the unbearable thought of solitude, as the story closes on a dangerous note."}], "headline": "A smooth, irresistible groove that cradles a dangerous fantasy of love pushed to its breaking point.", "key_lines": [{"line": "Hate to see you happy if I''m not the one drivin''", "insight": "Not just jealousy, but a need for control over the other person''s joy and destiny, a deeply possessive viewpoint."}, {"line": "If I can''t have you, no one should", "insight": "The ultimate declaration of possessive love, transforming desire into a zero-sum game where self-interest dictates the rules."}, {"line": "Rather be in jail than alone", "insight": "The unbearable weight of solitude, making any consequence, even incarceration, preferable to the emptiness of isolation."}, {"line": "Now I''m in the basement plannin'' home invasion", "insight": "The mundane setting for escalating dark thoughts, making the fantasy feel disturbingly real and close to home."}, {"line": "I did it all for love", "insight": "A twisted rationalization, presenting extreme and violent actions as the logical, selfless outcome of deep affection."}], "compound_mood": "Obsessive Yearning", "sonic_texture": "A smooth, undulating R&B beat lays down a seductive groove, with SZA''s cool vocals drifting over a low-key trap pulse. There''s a persistent, slightly melancholic warmth in the production, masking the lyrical tension with an effortless, danceable sway.", "audio_features": {"tempo": 88.98, "energy": 0.735, "valence": 0.418, "liveness": 0.161, "loudness": -5.747, "speechiness": 0.0391, "acousticness": 0.0521, "danceability": 0.644, "instrumentalness": 0.144}, "interpretation": "It''s not just about a murderous fantasy; it''s a raw confession of the terrifying depths of possessive love and the desperate fear of being utterly alone. The violent imagery becomes a desperate expression of a love that can''t let go, even when it knows it should, revealing the dangerous logic of a heart pushed to extremes.", "mood_description": "A cool, laid-back beat draws you in, but underneath the effortless flow, a simmering frustration starts to boil. It feels like dancing slowly while the darkest thoughts flicker at the edges of your mind."}', 'google:gemini-2.5-flash', '2', 5115, NULL, '2026-04-08 05:28:09.742937+00', '2026-04-08 05:28:09.742937+00', NULL, NULL, NULL, NULL),
	('3a47c640-721f-4909-b9be-781b2b308113', 'd91b3121-99a3-49de-abea-befefc5ad42c', '{"themes": [{"name": "territorial dominance", "description": "Claiming undisputed authority and legacy within a specific cultural space, dismissing any challengers as illegitimate."}, {"name": "predatory accusations", "description": "Directly and repeatedly leveling severe allegations of sexual misconduct against a rival, weaponizing deeply unsettling claims."}, {"name": "cultural appropriation", "description": "Criticizing the adoption of Black culture and community connections as a means to gain commercial success or street credibility."}, {"name": "collective rejection", "description": "Framing a personal feud as a broader community''s unified dismissal and ostracization of an unwelcome presence."}], "journey": [{"mood": "Eerie confidence", "section": "Opening Salvo", "description": "A chilling whisper sets a dark tone, then a confident beat immediately drops, launching into a relentless barrage of personal attacks and accusations that establish dominance."}, {"mood": "Unrelenting indictment", "section": "Scathing Exposé", "description": "The rhythmic momentum carries forward, but the words sharpen into deeply uncomfortable allegations, creating a public spectacle of moral condemnation while maintaining an undeniable swagger."}, {"mood": "Unifying dismissal", "section": "Collective Proclamation", "description": "The song explodes into a hypnotic, undeniable chant, transforming the personal beef into a communal rallying cry, a public declaration of who belongs and who doesn''t."}, {"mood": "Authoritative exposé", "section": "Cultural Reckoning", "description": "More layers of betrayal and inauthenticity are peeled back, extending the attack to cultural heritage and industry practices, delivered with unflinching authority over the persistent beat."}, {"mood": "Exultant mockery", "section": "Celebratory Dismissal", "description": "The insults become a catchy, communal taunt, turning the rival''s downfall into a dance-along event, with instructions to move as the final, triumphant dismissal echoes."}], "headline": "The absolute confidence of an undisputed champion, turning a personal feud into a communal declaration of victory.", "key_lines": [{"line": "Say, Drake, I hear you like ''em youngYou better not ever go to cell block one", "insight": "The blunt, public accusation that shifts from rumor to a direct warning of legal consequences."}, {"line": "Certified Lover Boy? Certified pedophiles", "insight": "Transforming a brand identity into a damning indictment, crystallizing the central, darkest accusation."}, {"line": "They not like us, they not like us, they not like us", "insight": "A potent, unifying chant that draws a clear line of demarcation, solidifying community against an outsider."}, {"line": "No, you not a colleague, you a fuckin'' colonizer", "insight": "Rejecting any pretense of equality or mutual respect, instead labeling the rival as an exploiter of culture."}, {"line": "Then step this way, step that way", "insight": "Turning a personal attack into a dance instruction, transforming humiliation into a collective, physical celebration."}], "compound_mood": "Triumphant Condemnation", "sonic_texture": "A pulsating G-funk bassline drives a propulsive, almost hypnotic rhythm, layered with sharp, declarative vocal delivery and occasional eerie synth accents, all designed for maximum dancefloor impact.", "audio_features": {"tempo": 101.061, "energy": 0.472, "valence": 0.214, "liveness": 0.141, "loudness": -7.001, "speechiness": 0.0776, "acousticness": 0.0107, "danceability": 0.898, "instrumentalness": 0}, "interpretation": "This isn''t just a diss track; it''s a statement of cultural ownership and a community''s rejection of an outsider. Leveraging serious allegations, it solidifies a narrative of moral and artistic superiority, turning a personal beef into a collective indictment. The danceable beat paradoxically amplifies the harshness, making the condemnation feel inescapable, a public execution on the dancefloor.", "mood_description": "A swaggering beat propels accusations forward, forcing movement even as the words cut deep. It''s a party anthem for an enemy''s downfall."}', 'google:gemini-2.5-flash', '2', 9934, NULL, '2026-04-08 05:28:32.539264+00', '2026-04-08 05:28:32.539264+00', NULL, NULL, NULL, NULL),
	('64380742-0796-46f8-80c8-1875e797cc49', '462d171c-27ff-4bec-a2d0-303c2b97f739', '{"themes": [{"name": "rebellious refusal", "description": "Rejecting external demands, even to a destructive degree, choosing to stand firm against perceived injustices."}, {"name": "self-punishment", "description": "A belief in deserving pain, actively inflicting it as a form of reclaiming agency or atonement."}, {"name": "societal burden", "description": "The overwhelming feeling of being crushed by compulsory obligations and the hypocrisy of those who impose them."}, {"name": "martyrdom", "description": "A willingness to suffer greatly rather than submit, drawing on imagery of ultimate sacrifice."}], "journey": [{"mood": "self-condemning plea", "section": "Verse 1", "description": "A raw confession of unworthiness, followed by a sudden widening of perspective to universal suffering, hinting at shared burdens."}, {"mood": "fierce confrontation", "section": "Verse 2", "description": "A direct challenge to authority, drawing a line in the sand with images of ultimate sacrifice, daring others to enforce their will."}, {"mood": "internalized struggle", "section": "Verse 3", "description": "The focus shifts inward, redirecting the defiance into a choice of self-inflicted pain, reclaiming agency over one''s own suffering."}, {"mood": "lingering anguish", "section": "Outro", "description": "Wordless vocalizations echo the weight of the previous declarations, a mournful, drawn-out consequence of the struggle that hangs in the air."}], "headline": "A desperate refusal to submit, choosing self-punishment and defiance over compromise with external demands.", "key_lines": [{"line": "I should burn in hell", "insight": "The profound weight of past wrongs, a self-imposed sentence echoing deep-seated guilt."}, {"line": "Nobody deserves this", "insight": "A sudden moment of empathy amidst self-loathing, extending suffering beyond oneself to all."}, {"line": "You''re gonna have to nail me down", "insight": "An unyielding refusal to yield, choosing ultimate sacrifice over submission to an unwanted demand."}, {"line": "Doctor, doctor, heal yourself", "insight": "A biting challenge to hypocrisy, demanding accountability from those in positions of power or judgment."}, {"line": "I will break my own heart", "insight": "Reclaiming agency over pain, choosing self-destruction rather than having it forced or inflicted by others."}], "compound_mood": "Resentful Defiance", "sonic_texture": "A raw, unvarnished energy pervades, with a stark and direct feel that mirrors the defiant, confrontational lyrics.", "interpretation": "A refusal to conform, even if it means self-destruction, driven by a deep sense of injustice and perhaps unworthiness. The narrative links societal obligations with a personal martyrdom, suggesting that some principles are worth sacrificing everything for, even one''s own well-being.", "mood_description": "A raw, guttural cry against forced compliance, where anger and self-loathing collide in a desperate stand."}', 'google:gemini-2.5-flash', '2', 4155, NULL, '2026-04-08 05:28:46.699098+00', '2026-04-08 05:28:46.699098+00', NULL, NULL, NULL, NULL),
	('71964440-1e91-45a0-a811-dca40ad4d5a1', '23089639-7c1d-4fad-9ebc-d102d2cee38a', '{"themes": [{"name": "fragile happiness", "description": "The realization that even the best moments are temporary and can be taken away."}, {"name": "fear of loss", "description": "The overwhelming anxiety that comes with finding something precious, making its potential absence unbearable."}, {"name": "spiritual bargaining", "description": "Pleading with a higher power to preserve the good things given, acknowledging divine control over one''s fortune."}, {"name": "post-struggle peace", "description": "Experiencing a calm and stable period after enduring significant personal hardship and chaos."}], "journey": [{"mood": "Reflective peace", "section": "Verse 1", "description": "Finding unexpected calm after a long struggle, everything finally clicking into place with family, love, and a sense of belonging."}, {"mood": "Sudden dread", "section": "Verse 1 (transition)", "description": "A quiet, unsettling awareness that this perfect moment is fragile, a gift that could just as easily be reclaimed."}, {"mood": "Desperate plea", "section": "Pre-Chorus / Chorus", "description": "The quiet fear erupts into a raw, urgent cry, begging for these precious things to remain, a heartfelt prayer against inevitable change."}, {"mood": "Inner turmoil", "section": "Verse 2", "description": "Despite outward peace, an internal battle rages, haunted by the question of why good things always seem to disappear, fueling the fear of impending loss."}, {"mood": "Lingering anxiety", "section": "Outro", "description": "The pleas persist, echoing with a deep-seated need, the voice fading but the desperate longing for security remaining unresolved."}], "headline": "A tender, overwhelming joy, shadowed by the deep terror that every beautiful thing could vanish in an instant.", "key_lines": [{"line": "But I know the things He gives me, He can take away", "insight": "The divine blessing is also a source of terrifying vulnerability."}, {"line": "But there''s no man as terrified as the man who stands to lose you", "insight": "The depth of love creates an equally profound capacity for fear."}, {"line": "If everything''s good and it''s great, why do I sit and wait ''til it''s gone?", "insight": "The mind sabotages peace by anticipating its end, even when things are perfect."}, {"line": "Don''t take These beautiful things that I''ve got", "insight": "A primal, simple prayer to keep what brings joy, uttered from a place of deep need."}], "compound_mood": "Anxious Contentment", "sonic_texture": "Earnest, powerful vocals rise over a dynamic pop-rock arrangement of driving drums and layered guitars. It builds with a raw, anthemic feel, carrying a weight of emotion that feels more pleading than purely energetic.", "audio_features": {"tempo": 105.029, "energy": 0.471, "valence": 0.219, "liveness": 0.14, "loudness": -5.692, "speechiness": 0.0603, "acousticness": 0.151, "danceability": 0.472, "instrumentalness": 0}, "interpretation": "The agonizing fear that accompanies true happiness, especially after a period of struggle. When life finally feels good, the vulnerability to lose it becomes overwhelming, leading to a desperate, almost spiritual, plea to hold onto the \"beautiful things\" found.", "mood_description": "A rising swell of heartfelt emotion, caught between the warmth of newfound happiness and the chilling dread of it all slipping away."}', 'google:gemini-2.5-flash', '2', 4898, NULL, '2026-04-08 05:29:02.129842+00', '2026-04-08 05:29:02.129842+00', NULL, NULL, NULL, NULL),
	('d0a85ceb-b82c-4600-8f65-019183227722', 'acb2449c-e1eb-49da-8fc3-e62b01657013', '{"themes": [{"name": "eternal commitment", "description": "An unwavering promise of love that extends beyond life itself, a desire for a bond that death cannot sever."}, {"name": "self-sabotage", "description": "A loved one''s internal battle with self-worth, pushing away affection and questioning the validity of being loved."}, {"name": "fated connection", "description": "The feeling of having known someone across lifetimes, suggesting a spiritual or destined bond."}, {"name": "unconditional love", "description": "Loving someone completely, even when they struggle to accept that love or recognize their own value."}], "journey": [{"mood": "immediate longing", "section": "Intro / Verse 1", "description": "A raw, unyielding declaration of a love that promises to last beyond life itself, bordering on an almost possessive devotion."}, {"mood": "expansive pledge", "section": "Refrain / Pre-Chorus / Chorus", "description": "An undeniable bond takes hold, moving past the idea of being better off alone. There''s an underlying tremble of emotion, almost overwhelmed by the depth of feeling that commits to forever."}, {"mood": "gentle frustration", "section": "Verse 2", "description": "A pivot to trying to make a loved one see their own beauty and worth, encountering their deep-seated self-doubt and resistance with a mix of understanding and exasperation."}, {"mood": "reassuring embrace", "section": "Pre-Chorus / Chorus (Reprise)", "description": "The unwavering promise returns, now laced with the ache of wanting to reassure and prevent a goodbye, despite the partner''s internal struggles that threaten the connection."}, {"mood": "destined affirmation", "section": "Post-Chorus", "description": "A comforting whisper of destiny, affirming a love that feels ancient and undeniable, ending with a soft, knowing certainty that brushes away any surprise or doubt."}], "headline": "A profound, fated love that demands permanence, even as it battles the partner''s own shadows and self-doubt.", "key_lines": [{"line": "''Til I''m in the grave ''Til I rot away, dead and buried", "insight": "A commitment that transcends life, a literal intertwining with fate itself."}, {"line": "Nothin'' left to lose without my baby", "insight": "Utter vulnerability, where identity and purpose hinge entirely on the presence of another."}, {"line": "Birds of a feather, we should stick together, I know", "insight": "The profound recognition that a solitary path is no longer desirable, a deep sense of belonging found in connection."}, {"line": "Say you wanna quit, don''t be stupid", "insight": "A blunt, almost exasperated plea for a partner to stop undermining their own happiness and the love they share."}, {"line": "I love you, don''t act so surprised", "insight": "A definitive, almost final statement of affection, dismissing any lingering disbelief with a knowing confidence."}], "compound_mood": "Fervent Devotion", "sonic_texture": "A smooth, mid-tempo pop groove with a relaxed, almost swaying rhythm. The vocals are clear and intimate, floating over warm, layered synths and a gentle, persistent bassline that grounds the emotional intensity without overpowering it.", "audio_features": {"tempo": 104.978, "energy": 0.507, "valence": 0.438, "liveness": 0.117, "loudness": -10.171, "speechiness": 0.0358, "acousticness": 0.2, "danceability": 0.747, "instrumentalness": 0.0608}, "interpretation": "It''s about a love so powerful it defies logic and self-preservation, characterized by one person''s unshakeable belief in a connection. This intense bond is tested by the partner''s struggle to accept that love or see their own worth, hinting at a dynamic where one person is giving everything while the other is withdrawing or pushing away due to deep-seated insecurity.", "mood_description": "A warm, pulsing groove carries an intense, almost desperate plea for a love that lasts forever. The air feels thick with devotion, yet a quiet urgency hums underneath."}', 'google:gemini-2.5-flash', '2', 5473, NULL, '2026-04-08 05:29:19.093293+00', '2026-04-08 05:29:19.093293+00', NULL, NULL, NULL, NULL),
	('a5ccb638-bdfc-4068-b888-9aaee4d92907', '93d580b3-10ae-4123-871c-b3f2508256b6', '{"themes": [{"name": "shattered expectations", "description": "The painful realization that promises of forever can break, leaving behind a profound sense of disbelief."}, {"name": "ghosts in familiar places", "description": "Everywhere feels haunted by memories of a past relationship, making it impossible to escape the reminders."}, {"name": "the other woman", "description": "The specific sting of an ex moving on to someone who embodies all your insecurities."}, {"name": "lonely independence", "description": "A newly acquired freedom that feels hollow and isolating without the person it was meant to be shared with."}], "journey": [{"mood": "grieving independence", "section": "Verse 1", "description": "The symbol of newfound freedom, a driver''s license, becomes a vehicle for tears and a stark reminder of an absent love."}, {"mood": "crushing comparison", "section": "Verse 2", "description": "A rumored new partner ignites deep insecurities, questioning worth and the possibility of ever loving again."}, {"mood": "disbelieving pain", "section": "Chorus", "description": "An anguished cry of confusion and hurt, wondering how someone could be so effortlessly okay after everything."}, {"mood": "lingering obsession", "section": "Verse 3", "description": "Friends are tired of the sorrow, but the memories are too real, driving through old streets imagining a shared past."}, {"mood": "overwhelming presence", "section": "Bridge", "description": "Every corner, every sound, every familiar spot brings a fresh wave of memories, culminating in a raw, undeniable admission of enduring love."}, {"mood": "echoing emptiness", "section": "Outro", "description": "The repeated promise of forever now rings hollow, as the drive continues alone, past a street that used to mean home."}], "headline": "A crushing first heartbreak, every familiar road a cruel mirror reflecting a lost future.", "key_lines": [{"line": "But today, I drove through the suburbsCrying ''cause you weren''t around", "insight": "The independence once eagerly anticipated now serves only to magnify the emptiness."}, {"line": "She''s everything I''m insecure about", "insight": "The sudden, devastating clarity of how easily you can be replaced by your deepest fears."}, {"line": "And I just can''t imagine how you could be so okay now that I''m gone", "insight": "The baffling, infuriating calm of someone who appears untouched by the wreckage of a shared past."}, {"line": "Guess you didn''t mean what you wrote in that song about me", "insight": "The gut punch of realizing past declarations of love were a performance, not a promise."}, {"line": "Can''t drive past the places we used to go to ''Cause I still fuckin'' love you, babe", "insight": "An unfiltered scream of enduring affection that refuses to let go, despite everything."}], "compound_mood": "Anguished Longing", "sonic_texture": "A somber piano opening gives way to building orchestral swells and a driving drum beat, layering raw, emotional vocals with subtle atmospheric backing. The sound feels like a night drive through heavy rain, emotionally turbulent yet deeply intimate.", "interpretation": "The bitter irony of achieving a long-anticipated milestone of freedom, only for it to expose the gaping hole left by a lost love. Every familiar route becomes a painful replay of shared dreams, while the casual ease with which an ex moves on shatters any illusion of their past sincerity. It''s the bewildering pain of watching someone become a stranger, taking all the shared history with them.", "mood_description": "Driving through familiar streets, each turn a fresh pang of loss, where new freedom is just a heavy reminder of what''s missing. The world moves on, but the ache remains, raw and exposed."}', 'google:gemini-2.5-flash', '2', 6130, NULL, '2026-04-08 05:29:38.711449+00', '2026-04-08 05:29:38.711449+00', NULL, NULL, NULL, NULL),
	('efbb9f33-fcf7-4d26-8220-7ab0b2c9aa7e', '4b92eb17-60f6-41ce-849a-a9bd905a9282', '{"themes": [{"name": "finding queer community", "description": "Discovering a sense of home and acceptance in queer spaces, particularly West Hollywood, after feeling out of place elsewhere."}, {"name": "parental disappointment", "description": "The painful reality of knowing personal happiness and authenticity will clash with a parent''s hopes and values, causing distress."}, {"name": "midwest escape", "description": "The urgent need to leave a small, conservative hometown to pursue a life that aligns with one''s true self."}, {"name": "defiant self-acceptance", "description": "Boldly embracing an identity and lifestyle despite anticipated judgment and pushback from those who wish you''d stayed the same."}], "journey": [{"mood": "yearning freedom", "section": "Verse 1 / Refrain", "description": "The pull of a life elsewhere begins, a vision of L.A. and a place where everyone can be their true self, despite the unspoken wishes of home."}, {"mood": "exultant defiance", "section": "Pre-Chorus / Chorus", "description": "The fantasy takes hold, embracing the ''pink pony girl'' identity on stage, knowing it will shock and disappoint, but feeling truly at home in the moment."}, {"mood": "realized joy", "section": "Verse 2 / Refrain", "description": "The dream is now reality, a vibrant club scene affirming the decision to leave, every wild night a confirmation of freedom and no regrets."}, {"mood": "lingering connection", "section": "Bridge", "description": "A brief, tender pause acknowledging that home and family aren''t forgotten, a soft echo of a mother''s voice still heard across the miles, a reminder of what was left behind."}, {"mood": "unwavering commitment", "section": "Chorus / Outro", "description": "The commitment to this new life solidifies, the dancing continues, a persistent, joyous declaration of resilience and a refusal to turn back, fading out on a note of pure, ongoing liberation."}], "headline": "A vibrant escape from expectation, celebrating a new identity with defiant joy, even as echoes of home still sting.", "key_lines": [{"line": "Won''t make my mama proud, it''s gonna cause a scene", "insight": "The painful awareness that authenticity comes with a cost, predicting the emotional clash with parental expectations."}, {"line": "On the stage in my heels, it''s where I belong", "insight": "Finding a deep, affirming sense of home and purpose in unexpected, vibrant spaces."}, {"line": "Every night''s another reason why I left it all", "insight": "The constant validation of a life-altering decision, affirming that the leap was worth every sacrifice."}, {"line": "I can hear your Southern drawl a thousand miles away, saying", "insight": "The persistent, internal echo of a parent''s voice and values, even after physically leaving them behind."}], "compound_mood": "Joyful Rebellion", "sonic_texture": "Pulsing synth bass and glittery, layered synthesizers create a driving, danceable beat. Clean, bright vocals float above a rich electronic soundscape, feeling both expansive and intimately personal.", "audio_features": {"tempo": 106.719, "energy": 0.65, "valence": 0.507, "liveness": 0.11, "loudness": -6.199, "speechiness": 0.0474, "acousticness": 0.399, "danceability": 0.61, "instrumentalness": 0}, "interpretation": "This is about the exhilarating, yet often painful, journey of self-discovery and embracing a queer identity, particularly when it means breaking from conservative family expectations and a restrictive upbringing. It''s a vivid depiction of finding belonging and joy in new spaces, even as the emotional ties to the past persist, creating a bittersweet tension between newfound freedom and familial disapproval. The music amplifies this feeling, providing an almost celebratory soundtrack to a deeply personal and defiant act.", "mood_description": "A rush of shimmering synth-pop energy sweeps you onto the dance floor. It feels like pure liberation, but there''s an undercurrent of knowing this freedom comes at a cost."}', 'google:gemini-2.5-flash', '2', 5451, NULL, '2026-04-08 05:29:51.318433+00', '2026-04-08 05:29:51.318433+00', NULL, NULL, NULL, NULL),
	('9a63a928-2563-445d-b2df-515244bb6e4c', 'a0a8200e-97bf-4e2e-abc0-ed3074c66137', '{"themes": [{"name": "self-blame", "description": "Taking responsibility for the breakdown of a relationship, even when pain is mutual."}, {"name": "destructive love", "description": "A love so intense it feels like a natural disaster, shaking the foundation of everything."}, {"name": "desperate pleading", "description": "An urgent, almost frantic begging for a partner to stay, despite the clear signs of trouble."}, {"name": "emotional dependency", "description": "The feeling of needing someone so intensely that their departure feels like the world ending."}], "journey": [{"mood": "urgent anticipation", "section": "Intro", "description": "A repetitive, almost hypnotic chant sets a tone of earnest conviction, hinting at a crucial confession about to unfold."}, {"mood": "shaken heartbreak", "section": "Chorus", "description": "The confession bursts out: a love so powerful it’s a seismic event, joyfully unsettling but also breaking hearts, a dizzying blend of ecstasy and pain."}, {"mood": "vulnerable plea", "section": "Refrain", "description": "A desperate, repeated cry of ''Don''t leave, it''s my fault'' emerges, revealing a deep sense of responsibility and a fear of total collapse, a double meaning of physical and emotional fault lines."}, {"mood": "street-level anxiety", "section": "Verse", "description": "A different voice enters, recounting anxieties of betrayal and street life, a brief diversion from the emotional core, yet concluding with a surprising, quiet declaration of being ''so in love.''"}, {"mood": "desperate negotiation", "section": "Bridge", "description": "The emotional core returns, directly confronting the lack of communication, pleading for clarity and confirmation, wanting honesty over conflict or secondhand rumors."}, {"mood": "fading desperation", "section": "Outro", "description": "The pleas become an echo, repeating ''Don''t leave, it''s my fault'' as the sound gently recedes, leaving a lingering sense of unfulfilled longing."}], "headline": "A frantic, almost pleading negotiation with a love that''s violently shaking everything apart, desperately trying to avert the inevitable collapse.", "key_lines": [{"line": "Bitch, I cannot fall short", "insight": "The fierce determination to succeed or measure up, even in the face of emotional collapse."}, {"line": "''Cause you make my earth quake", "insight": "A love so intense it''s both thrilling and terrifyingly destructive, shaking the very ground beneath you."}, {"line": "Don''t leave, it''s my fault", "insight": "The crushing weight of self-blame, taking ownership for a relationship''s breakdown while begging for its survival."}, {"line": "I just need some confirmation on how you feel, for real", "insight": "The desperate need for clarity and honesty when lost in emotional uncertainty, tired of guessing games."}, {"line": "So in love", "insight": "A simple, stark admission that cuts through the chaos, revealing the raw, unwavering core of affection despite everything."}], "compound_mood": "Turbulent Longing", "sonic_texture": "Warm, slightly melancholic synths drift over a driving, almost shuffling beat. There''s a raw, live energy to the vocals, layered with smooth backing harmonies that give it a soulful, pleading quality. The bass is prominent, giving it a solid, grounding feel despite the emotional turbulence.", "audio_features": {"tempo": 79.635, "energy": 0.498, "valence": 0.413, "liveness": 0.795, "loudness": -8.866, "speechiness": 0.0685, "acousticness": 0.23, "danceability": 0.554, "instrumentalness": 0.00000598}, "interpretation": "The agonizing truth that love, even when it feels like an existential tremor, makes you cling harder, desperately negotiating for a future with someone who''s already tearing you apart. It''s a raw confession of fault and dependency, where the emotional chaos of heartbreak is felt as a physical, destabilizing force, even as the groove keeps a steady, almost hypnotic pull.", "mood_description": "An anxious urgency pulses beneath a heartfelt plea. It feels like the ground is shifting, but there''s a desperate need to keep things from falling apart."}', 'google:gemini-2.5-flash', '2', 6027, NULL, '2026-04-08 05:30:09.371974+00', '2026-04-08 05:30:09.371974+00', NULL, NULL, NULL, NULL),
	('62373b1b-c19d-47d2-afff-8f324b84acb2', '140ebf68-f075-45f4-83c1-893170346487', '{"themes": [{"name": "desperate yearning", "description": "A profound emotional need for another person''s presence to find clarity and stability amidst personal turmoil."}, {"name": "urban isolation", "description": "Experiencing deep loneliness and a sense of being lost within the stimulating but ultimately empty backdrop of a \"Sin City\" environment."}, {"name": "self-medication", "description": "Using external means, whether substances or reckless pursuits, to cope with internal pain and vulnerability."}, {"name": "blurred reality", "description": "A state where one''s perception is clouded by overwhelming experiences, making it hard to see clearly without a grounding connection."}], "journey": [{"mood": "raw vulnerability", "section": "Opening Confession", "description": "A quiet, almost hesitant opening reveals a deep-seated loneliness and a plea for connection, hinting at withdrawals and a desperate sensitivity to touch."}, {"mood": "uneasy isolation", "section": "Sin City''s Emptiness", "description": "The energy swells as the cold, empty city is revealed, a place where judgment is absent but clarity is impossible without the other person."}, {"mood": "frantic yearning", "section": "Blinding Desperation", "description": "An explosive surge of energy as the realization hits: blinded and drowning, only one person can be trusted, making the need urgent and overwhelming."}, {"mood": "urgent haste", "section": "Reckless Pursuit", "description": "Time is running out, and the drive becomes more frantic, hitting the road \"in overdrive\" in a desperate attempt to find that crucial connection before dawn."}, {"mood": "steadfast declaration", "section": "Unwavering Resolve", "description": "A brief pause in the urgency to declare a firm commitment, a promise never to let go this time, too important for a phone call."}, {"mood": "persistent longing", "section": "Lingering Plea", "description": "The initial plea echoes, repeating the desperate state of being blinded and unable to rest until that vital touch is felt, fading out with the unresolved yearning."}], "headline": "A desperate chase through neon nights, seeking a singular touch to cut through the haze of a life spinning out of control.", "key_lines": [{"line": "I''m goin'' through withdrawals", "insight": "The physical and emotional cost of a life lived on the edge, longing for relief."}, {"line": "I can''t see clearly when you''re gone", "insight": "Complete dependence on another person to make sense of a chaotic, blurry world."}, {"line": "ooh, I''m blinded by the lights", "insight": "The overwhelming sensory input and dangerous lifestyle have obscured reality, leading to a state of desperate disorientation."}, {"line": "Oh, when I''m like this, you''re the one I trust", "insight": "Amidst chaos and self-inflicted wounds, a singular person becomes the last bastion of safety and faith."}, {"line": "Will never let you go this time", "insight": "A promise born from past mistakes and the fear of losing the one stabilizing force."}], "compound_mood": "Desperate Urgency", "sonic_texture": "A propulsive 80s synthwave throb, with glittering, layered synthesizers driving a relentless beat. The sound is sleek and electronic, creating a vibrant, almost dizzying backdrop for the desperate vocals.", "audio_features": {"tempo": 171.001, "energy": 0.73, "valence": 0.334, "liveness": 0.0897, "loudness": -5.94, "speechiness": 0.0598, "acousticness": 0.00143, "danceability": 0.513, "instrumentalness": 0.0000954}, "interpretation": "A life of destructive hedonism collides with a desperate need for genuine human connection. The \"blinding lights\" represent the overwhelming chaos and blurred reality of a life lived on the edge, where substances and fleeting encounters leave one vulnerable and aching for a singular, anchoring touch. It''s a stark portrayal of seeking salvation in another person when everything else is falling apart, even as the pursuit itself feels reckless and out of control.", "mood_description": "A relentless synth-pop drive pushes you forward, but a profound loneliness tugs at the edges, making every flash of light a reminder of what''s missing. It feels like chasing something vital, just out of reach."}', 'google:gemini-2.5-flash', '2', 6189, NULL, '2026-04-08 05:30:31.495453+00', '2026-04-08 05:30:31.495453+00', NULL, NULL, NULL, NULL),
	('0d60a2df-db45-4f33-8a0b-53dc25c6c8d1', 'df14a8d9-303c-4fe9-a862-b31dfcc0b510', '{"themes": [{"name": "irreplaceable past", "description": "A constant pull backward to a time or person that cannot be brought back."}, {"name": "lonely independence", "description": "Finding yourself alone and having to navigate new realities without old support systems."}, {"name": "pervasive change", "description": "The inescapable feeling that nothing is truly the same as it once was, especially after a collective upheaval."}, {"name": "emotional masking", "description": "Projecting an upbeat facade while internally grappling with heavy feelings of loss and solitude."}], "journey": [{"mood": "Playful connection", "section": "Intro", "description": "A warm, intimate voice cuts through, a playful reminder of connection before plunging into the heart of things."}, {"mood": "Stuck longing", "section": "Verse 1", "description": "A sudden weight. You''re held back, stuck in a loop of past conversations, searching for a familiar hand to hold."}, {"mood": "Frantic acceptance", "section": "Chorus", "description": "The world shrinks to just you and a memory. The beat quickens, almost frantic, trying to outrun the undeniable truth that things are irrevocably altered."}, {"mood": "Vulnerable isolation", "section": "Verse 2", "description": "A phone rings, a voice from the outside checking in, revealing a deeper loneliness, a quiet desperation for help that isn''t coming."}, {"mood": "Desperate distraction", "section": "Bridge", "description": "A brief, sharp break. Thoughts scatter about escaping and not wanting to revisit painful topics, a desperate rush for distraction."}, {"mood": "Resigned echo", "section": "Outro", "description": "The frantic energy slowly gives way to a resigned acceptance, the echo of what was fading into the distance but never fully disappearing."}], "headline": "A frantic attempt to dance away the past, even as its ghosts whisper in your ear.", "key_lines": [{"line": "Gravity''s holdin'' me back", "insight": "An invisible force keeps you tethered to a previous life, unable to fully step into the new."}, {"line": "You know it''s not the same as it was", "insight": "The stark, repeated acknowledgment that a fundamental shift has occurred, leaving a permanent mark."}, {"line": "Harry, you''re no good alone", "insight": "The painful truth from an outside perspective, highlighting a vulnerable reliance on others for well-being."}, {"line": "Nobody''s coming to help", "insight": "The gut-wrenching realization that you''re truly on your own, facing challenges without a safety net."}, {"line": "I don''t wanna talk about the way that it was", "insight": "A desperate attempt to shut down introspection and avoid reliving a past that still hurts."}], "compound_mood": "Frenetic Longing", "sonic_texture": "A relentlessly pulsing synth bass underpins bright, shimmering keyboard melodies and a tight, driving drum machine beat. Vocals are upfront and clean, carrying a wistful ache despite the electrifying, dance-oriented production.", "audio_features": {"tempo": 173.93, "energy": 0.731, "valence": 0.662, "liveness": 0.311, "loudness": -5.338, "speechiness": 0.0557, "acousticness": 0.342, "danceability": 0.52, "instrumentalness": 0.00101}, "interpretation": "The dizzying realization that life has fundamentally shifted, leaving a profound sense of isolation and an unshakeable longing for what once was. Even with a vibrant, pulsating beat pushing forward, the lyrics confess a deep struggle to accept this new reality, portraying a person trapped between the need to move on and the pull of irreplaceable memories and connections.", "mood_description": "An electric current of synth-pop energy courses through you, making your body move, but your mind stays fixed on a past that feels miles away."}', 'google:gemini-2.5-flash', '2', 5195, NULL, '2026-04-08 05:30:48.200793+00', '2026-04-08 05:30:48.200793+00', NULL, NULL, NULL, NULL),
	('6b01c0da-840d-4877-88bc-99f60696c11d', 'b194ad65-b64e-425a-8a67-6da6549b7044', '{"themes": [{"name": "perpetual immaturity", "description": "The endless cycle of childish behavior and irresponsibility in a romantic connection."}, {"name": "emotional burden", "description": "The heavy weight of being consistently responsible for another''s basic functions and emotional needs."}, {"name": "ironic self-awareness", "description": "Finding humor and perspective in a frustrating situation, even when it means acknowledging your own role in choosing it."}, {"name": "blaming the roots", "description": "Tracing current failings back to early influences, specifically a mother''s perceived over-coddling."}], "journey": [{"mood": "Annoyed observation", "section": "Intro/Verse 1", "description": "A sharp, observant start. Little details of incompetence pile up, leading to a quizzical, sarcastic question about the state of things."}, {"mood": "Biting accusation", "section": "Pre-Chorus/Chorus", "description": "The mood shifts to direct confrontation. A playful but firm takedown, naming the core problem with a catchy, undeniable hook."}, {"mood": "Exasperated insight", "section": "Verse 2", "description": "Deepening the frustration. Blame gets redirected, questioning fundamental survival skills with a knowing, almost comical exasperation."}, {"mood": "Ironic resignation", "section": "Bridge", "description": "A moment of self-reflection, tinged with dark humor. A sarcastic admission of a pattern, almost a prayer, acknowledging the absurdity of it all."}, {"mood": "Worn-out defiance", "section": "Chorus/Outro", "description": "The initial observations loop back, ending with a final, ironic acceptance of the situation, still wrapped in that danceable energy."}], "headline": "The exasperated eye-roll at a partner who refuses to grow up, set to a deceptively bright beat.", "key_lines": [{"line": "Did you just say you''re finished? Didn''t know we started", "insight": "The stark realization that you''re investing in something that was never truly reciprocal."}, {"line": "Man-child", "insight": "A perfectly distilled label for the frustratingly common archetype of an immature adult."}, {"line": "Never heard of self-care", "insight": "Pointing out a fundamental lack of personal responsibility in a cutting, almost childlike observation."}, {"line": "I choose to blame your mom", "insight": "A humorous yet pointed deflection of accountability, highlighting the absurdity of the situation."}, {"line": "And I swear they choose me, I''m not choosing them", "insight": "The wry, self-aware admission of an unfortunate, repeating dating pattern."}], "compound_mood": "Sarcastic Groove", "sonic_texture": "Bright, driving synths and a buoyant bassline underpin a clean, pop-forward vocal. It’s a danceable, high-energy track that feels effortlessly cool, with just a hint of sparkling sonic detail.", "audio_features": {"tempo": 123.01, "energy": 0.685, "valence": 0.811, "liveness": 0.317, "loudness": -5.087, "speechiness": 0.0572, "acousticness": 0.122, "danceability": 0.731, "instrumentalness": 0}, "interpretation": "The relentless emotional labor of parenting a grown man who should be a partner. It’s a weary recognition of repeated patterns, wrapped in a defiant, sarcastic shrug.", "mood_description": "An upbeat pop rhythm masks a sharp, witty frustration. It''s dancing through annoyance, a smile stretched thin as you deal with yet another childish mess."}', 'google:gemini-2.5-flash', '2', 5474, NULL, '2026-04-08 05:31:04.364851+00', '2026-04-08 05:31:04.364851+00', NULL, NULL, NULL, NULL),
	('013b0550-ba4f-4e1c-ac62-f7a4d9121da6', '9a35420c-309b-4df1-aa9f-a394ff5fadda', '{"themes": [{"name": "divine protection", "description": "Believing in a higher power or fate to shield from negativity and guide choices."}, {"name": "loyalty''s embrace", "description": "The profound importance of a small, trusted circle against a world of adversaries."}, {"name": "the cost of fame", "description": "The constant vigilance required against those who wish ill, and the emotional distance it creates."}, {"name": "hometown pride", "description": "A deep connection to roots and a commitment to uplifting the people and places that shaped one''s identity."}], "journey": [{"mood": "Anticipatory unease", "section": "Intro", "description": "A subtle hum of warning, hinting at unseen conflicts just beneath the surface."}, {"mood": "Defiant assertion", "section": "Verse 1", "description": "Laying down boundaries with a quiet resolve, aware of the envy and wishes of others, but choosing peace as a struggle."}, {"mood": "Fated resolve", "section": "Pre-Chorus", "description": "A sudden declaration of purpose, acknowledging internal struggles while committing to a path believed to be guided by destiny."}, {"mood": "Echoing threats", "section": "Chorus", "description": "The quiet warnings turn into a resounding chant, a reminder of the relentless negativity constantly aimed at success."}, {"mood": "Inner circle''s strength", "section": "Verse 2", "description": "Pulling back the curtain on the chosen few, revealing the unbreakable bonds that truly sustain, a stark contrast to external drama."}, {"mood": "Lingering affirmation", "section": "Outro", "description": "The chant slowly fades, leaving a final impression of resilience and the persistent belief in a predetermined path."}], "headline": "Navigating the perilous path of success, shielded by a divine belief even as shadows loom.", "key_lines": [{"line": "I only love my bed and my mama, I''m sorry", "insight": "A stark confession of where true affection lies, revealing the emotional walls built around success."}, {"line": "Don''t pull up at 6 a.m. to cuddle with me", "insight": "Setting clear boundaries on casual intimacy, asserting self-worth beyond fleeting desires."}, {"line": "Hope I got some brothers that outlive me", "insight": "A sobering reflection on mortality and the enduring legacy desired through loyal friendships."}, {"line": "I make sure that north-side eat", "insight": "A powerful declaration of commitment to hometown and community, ensuring their prosperity alongside personal success."}, {"line": "I can''t do this on my own, ayy", "insight": "Acknowledging the reliance on something greater than oneself, whether fate or a divine power, for guidance and strength."}], "compound_mood": "Guarded Confidence", "sonic_texture": "A heavy, thumping bassline anchors a sparse, confident beat. Whispering synth pads create a subtle atmospheric tension, while Drake''s laid-back yet assertive flow cuts through the deep, rhythmic groove.", "audio_features": {"tempo": 77.169, "energy": 0.449, "valence": 0.357, "liveness": 0.552, "loudness": -9.211, "speechiness": 0.109, "acousticness": 0.0332, "danceability": 0.754, "instrumentalness": 0.0000829}, "interpretation": "A testament to loyalty and self-preservation in the face of widespread animosity. It''s about holding onto a personal code and trusting in an almost fated path, even as external pressures threaten to crumble connections and peace. The cold pragmatism of fame requires a tight inner circle and a strong belief in an overarching plan.", "mood_description": "A steady, low-slung beat that carries a weight of expectation. There''s a quiet determination moving through the rhythm, constantly aware of unseen eyes."}', 'google:gemini-2.5-flash', '2', 6232, NULL, '2026-04-08 05:31:56.890598+00', '2026-04-08 05:31:56.890598+00', NULL, NULL, NULL, NULL),
	('a5490b39-de96-4476-96fd-77c6429f856b', 'c1d0a2e9-1758-478b-9f59-5f23502be75f', '{"themes": [{"name": "lost chances", "description": "Regretting not fully appreciating or capturing moments with someone important."}, {"name": "rooted belonging", "description": "Finding comfort and identity in local culture, friends, and family, particularly in Puerto Rico."}, {"name": "escapist revelry", "description": "Using partying and alcohol as a way to cope with underlying sadness or unaddressed feelings."}, {"name": "fading memory", "description": "The struggle to hold onto precious memories that are slowly becoming less clear."}], "journey": [{"mood": "distant hum", "section": "Intro", "description": "A quiet, almost observational hum, setting a scene of introspection before the story truly begins."}, {"mood": "bittersweet reflection", "section": "Verso 1", "description": "Sunsets in San Juan clash with a heavy heart, recalling missed moments and longing for a lost connection, even as friends and local life buzz around."}, {"mood": "aching regret", "section": "Estribillo", "description": "The deep, aching core of the regret surfaces, a quiet lament for forgotten embraces and unseen pictures, clinging to the familiar faces that remain."}, {"mood": "blurred denial", "section": "Verso 2", "description": "A fragile denial takes hold, pretending not to care while diving deeper into hazy celebration, seeking temporary oblivion from the lingering pain."}, {"mood": "raw connection", "section": "Interludio", "description": "A sudden, tender break in the haze, speaking directly to the crowd, pulling everyone in for a shared moment of gratitude and belonging before the party resumes."}, {"mood": "fading resignation", "section": "Outro", "description": "The regrets echo, mixed with a final, almost desperate plea for help and a slightly crass longing, as the night slowly fades into a blurry memory."}], "headline": "A hazy dance through past regrets, trying to find joy in the blur of present-day Puerto Rico.", "key_lines": [{"line": "Pero queriendo volver a la última vezQue a los ojos te miré", "insight": "The exact point where present enjoyment shatters against a specific, painful memory."}, {"line": "Debí tirar más fotos de cuando te tuve", "insight": "The quiet, crushing realization that not enough was done to preserve a cherished past."}, {"line": "Si me pregunta si aún pienso en ti, yo le digo que no", "insight": "The internal lie told to oneself and others, a protective shield against genuine feeling."}, {"line": "Vamo'' a disfrutar, que nunca se sabe si nos queda poco", "insight": "A frantic embrace of the present, driven by the fear of future loss and the passage of time."}, {"line": "Ojalá que los mío'' nunca se muden", "insight": "The desperate hope that some constants will remain, even as other connections dissolve."}], "compound_mood": "Wistful Daze", "sonic_texture": "A subdued reggaeton rhythm underpins a hazy soundscape of muted percussive elements and distant, longing melodies. It feels like a late-night, low-volume mix, with a gentle, persistent sway that hints at movement more than full-blown dance, occasionally punctuated by spoken word asides.", "audio_features": {"tempo": 136.02, "energy": 0.131, "valence": 0.032, "liveness": 0.0807, "loudness": -27.405, "speechiness": 0.0717, "acousticness": 0.177, "danceability": 0.625, "instrumentalness": 0.218}, "interpretation": "A danceable current of regret carries you through a night of distraction. Even surrounded by friends and the vibrant energy of San Juan, there''s a deep ache for past connections, a silent wish to relive moments that slipped away without enough photos or goodbyes.", "mood_description": "A slow, heavy sway of regret and longing, trying to find release in a hazy night out."}', 'google:gemini-2.5-flash', '2', 5503, NULL, '2026-04-08 05:32:12.908304+00', '2026-04-08 05:32:12.908304+00', NULL, NULL, NULL, NULL),
	('143e9296-5f71-42aa-b8d2-66cdf4826ca5', '03b0c165-6c9b-47d9-8e1e-131bddcaf106', '{"themes": [{"name": "voyeuristic jealousy", "description": "Watching an ex move on from a distance, feeling the sting of their new happiness and dissecting the new person."}, {"name": "bitter defense mechanisms", "description": "Using sarcasm and self-deprecating humor as a shield against the pain of seeing a former partner with someone new."}, {"name": "emotional ghosting", "description": "The feeling of emotional death after a breakup, even when trying to appear fine on the surface."}, {"name": "complicated empathy", "description": "A surprising flicker of understanding or even liking for the ''other'' person, adding a layer of confusion to the bitterness."}], "journey": [{"mood": "Peering in", "section": "Verse 1", "description": "Standing just outside, watching a former lover''s new life unfold, dissecting every detail with a mix of lingering hurt and cutting judgment."}, {"mood": "Pointed warning", "section": "Pre-Chorus", "description": "The internal monologue sharpens into a definitive judgment, a protective instinct stirring to caution the new person about past mistakes."}, {"mood": "Familiar sting", "section": "Chorus", "description": "A vivid, almost cinematic replay of a scene from the past, recognizing the comfortable intimacy with a fresh sting of what''s been lost."}, {"mood": "Conflicted chaos", "section": "Verse 2", "description": "A descent into petty jealousy and vivid memories, bouncing wildly between a surprising soft spot for the new person and a quick retraction back to bitter hatred."}, {"mood": "Ghostly defiance", "section": "Bridge", "description": "The facade crumbles, revealing the deep wounds and the feeling of having died when the other person walked away, leading to a defiant, almost haunting presence."}, {"mood": "Resigned clarity", "section": "Outro", "description": "The bitter truth settles in: the cycle of attraction and disappointment repeats, leaving a cynical acceptance of the game being played."}], "headline": "The relentless loop of post-breakup obsession, caught between cutting remarks and a surprising, almost reluctant, curiosity.", "key_lines": [{"line": "Living in your glass house, I''m outside, uh", "insight": "The vulnerable exposure of a new relationship, visible and judged from the periphery of a past connection."}, {"line": "Smiling through it all, yeah, that''s my life", "insight": "A sardonic self-awareness, acknowledging the performative facade maintained while privately reeling from pain."}, {"line": "Wait, I think I hate her, I''m not that evolved, I''m sorry", "insight": "The honest, immediate confession of falling short of an ideal self, succumbing to base, human emotion."}, {"line": "Said that I was fine, said it from my coffin", "insight": "The stark contrast between outward composure and the internal devastation felt after a significant loss."}, {"line": "And she''ll spend the night, catch me on your ceiling", "insight": "A lingering, almost spectral presence haunting the new relationship, a constant reminder of what came before."}], "compound_mood": "Frenetic Jealousy", "sonic_texture": "Driving indie pop with bright, propulsive drums and a clear, forward vocal delivery, balanced by a subtle undercurrent of acoustic warmth that keeps it grounded, even as the energy surges.", "audio_features": {"tempo": 108.548, "energy": 0.808, "valence": 0.372, "liveness": 0.159, "loudness": -4.169, "speechiness": 0.0368, "acousticness": 0.214, "danceability": 0.554, "instrumentalness": 0}, "interpretation": "The tangled mess of post-breakup emotions, where sharp wit and self-aware sarcasm barely hide the raw sting of jealousy and lingering attachment. It’s the internal battle between wishing an ex well and secretly wanting them to fail, all while observing their new life with a mix of judgment and morbid fascination.", "mood_description": "A rush of sharp-edged observations carried by a bright, urgent beat. It feels like dancing through a complicated, self-aware moment of intense, conflicted feelings."}', 'google:gemini-2.5-flash', '2', 5894, NULL, '2026-04-08 05:32:30.214914+00', '2026-04-08 05:32:30.214914+00', NULL, NULL, NULL, NULL);


